using System;
using System.Reflection;

class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("Metod çağırılır...");
        try
        {
            Type type = typeof(Person);
            object personInstance = Activator.CreateInstance(type);
            MethodInfo method = type.GetMethod("NonExistentMethod");
            if (method == null)
                throw new MissingMethodException("Metod tapılmadı.");
            method.Invoke(personInstance, null);
        }
        catch (MissingMethodException ex)
        {
            Console.WriteLine("Səhv baş verdi!");
            Console.WriteLine($"Səhv mesajı: {ex.Message}");
        }
    }
}

