    {
        Console.WriteLine("Refleksiya sınağı...");
        try
        {
            Type type = typeof(Calculator);
            object calcInstance = Activator.CreateInstance(type);
            MethodInfo method = type.GetMethod("Add");
            if (method == null)
                throw new MissingMethodException("Metod tapılmadı.");
            int result = (int)method.Invoke(calcInstance, new object[] { 5, 3 });
            Console.WriteLine($"Nəticə: 5 + 3 = {result}");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Səhv: {ex.Message}");
        }
    }
}

